     1→import { useState } from "react";
     2→import { AppLayout } from "@/components/layout";
     3→import { useListEvents, useBulkUpdateEvents, useDeleteEvent, useListSources } from "@workspace/api-client-react";
     4→import { Card } from "@/components/ui/card";
     5→import { Button } from "@/components/ui/button";
     6→import { Badge } from "@/components/ui/badge";
     7→import { Input } from "@/components/ui/input";
     8→import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
     9→import { Checkbox } from "@/components/ui/checkbox";
    10→import { format } from "date-fns";
    11→import { it } from "date-fns/locale";
    12→import { Search, Plus, Filter, AlertTriangle, CheckCircle2, XCircle, MapPin, Clock, Trash2, Eye } from "lucide-react";
    13→import { useQueryClient } from "@tanstack/react-query";
    14→import { useToast } from "@/components/ui/use-toast";
    15→
    16→export default function Eventi() {
    17→  const [statusFilter, setStatusFilter] = useState<string>("all");
    18→  const [sourceFilter, setSourceFilter] = useState<string>("all");
    19→  const [searchTerm, setSearchTerm] = useState("");
    20→  const [selectedIds, setSelectedIds] = useState<number[]>([]);
    21→
    22→  const { data: eventsData, isLoading } = useListEvents({
    23→    status: statusFilter !== "all" ? statusFilter : undefined,
    24→    sourceId: sourceFilter !== "all" ? Number(sourceFilter) : undefined,
    25→    search: searchTerm || undefined,
    26→    limit: 50,
    27→  });
    28→
    29→  const { data: sources } = useListSources();
    30→  const bulkMutation = useBulkUpdateEvents();
    31→  const deleteMutation = useDeleteEvent();
    32→  const queryClient = useQueryClient();
    33→  const { toast } = useToast();
    34→
    35→  const handleBulkAction = async (action: string) => {
    36→    if (selectedIds.length === 0) return;
    37→    try {
    38→      await bulkMutation.mutateAsync({ data: { ids: selectedIds, action } });
    39→      toast({ title: "Eventi aggiornati" });
    40→      setSelectedIds([]);
    41→      queryClient.invalidateQueries({ queryKey: ["/api/events"] });
    42→    } catch (e) {
    43→      toast({ title: "Errore", variant: "destructive" });
    44→    }
    45→  };
    46→
    47→  const toggleAll = (checked: boolean) => {
    48→    if (checked && eventsData) setSelectedIds(eventsData.events.map(e => e.id));
    49→    else setSelectedIds([]);
    50→  };
    51→
    52→  const toggleOne = (id: number) => {
    53→    setSelectedIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
    54→  };
    55→
    56→  const getStatusBadge = (status: string) => {
    57→    switch (status) {
    58→      case 'pending': return <Badge className="bg-amber-100 text-amber-700 border-amber-200 hover:bg-amber-100">In attesa</Badge>;
    59→      case 'approved': return <Badge className="bg-green-100 text-green-700 border-green-200 hover:bg-green-100">Approvato</Badge>;
    60→      case 'rejected': return <Badge className="bg-red-100 text-red-700 border-red-200 hover:bg-red-100">Rifiutato</Badge>;
    61→      default: return <Badge variant="outline">{status}</Badge>;
    62→    }
    63→  };
    64→
    65→  return (
    66→    <AppLayout>
    67→      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 mb-8">
    68→        <div>
    69→          <h1 className="text-3xl font-bold font-display text-foreground tracking-tight">Eventi</h1>
    70→          <p className="text-muted-foreground mt-1">Gestisci, revisiona e approva gli eventi per la newsletter.</p>
    71→        </div>
    72→        <Button className="shadow-md">
    73→          <Plus className="w-4 h-4 mr-2" />
    74→          Aggiungi Evento
    75→        </Button>
    76→      </div>
    77→
    78→      <div className="bg-card p-4 rounded-xl border border-border/50 mb-6 flex flex-col md:flex-row gap-4 shadow-sm">
    79→        <div className="flex-1 relative">
    80→          <Search className="w-4 h-4 absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
    81→          <Input 
    82→            placeholder="Cerca evento..." 
    83→            className="pl-9 bg-background"
    84→            value={searchTerm}
    85→            onChange={e => setSearchTerm(e.target.value)}
    86→          />
    87→        </div>
    88→        <div className="flex flex-wrap gap-3">
    89→          <Select value={statusFilter} onValueChange={setStatusFilter}>
    90→            <SelectTrigger className="w-[140px] bg-background">
    91→              <SelectValue placeholder="Stato" />
    92→            </SelectTrigger>
    93→            <SelectContent>
    94→              <SelectItem value="all">Tutti gli stati</SelectItem>
    95→              <SelectItem value="pending">In attesa</SelectItem>
    96→              <SelectItem value="approved">Approvati</SelectItem>
    97→              <SelectItem value="rejected">Rifiutati</SelectItem>
    98→            </SelectContent>
    99→          </Select>
   100→
   101→          <Select value={sourceFilter} onValueChange={setSourceFilter}>
   102→            <SelectTrigger className="w-[180px] bg-background">
   103→              <SelectValue placeholder="Tutte le fonti" />
   104→            </SelectTrigger>
   105→            <SelectContent>
   106→              <SelectItem value="all">Tutte le fonti</SelectItem>
   107→              {sources?.map(s => <SelectItem key={s.id} value={s.id.toString()}>{s.name}</SelectItem>)}
   108→            </SelectContent>
   109→          </Select>
   110→        </div>
   111→      </div>
   112→
   113→      {selectedIds.length > 0 && (
   114→        <div className="bg-primary/5 border border-primary/20 p-3 rounded-lg mb-4 flex items-center justify-between animate-in fade-in slide-in-from-top-2">
   115→          <span className="text-sm font-medium text-primary ml-2">{selectedIds.length} eventi selezionati</span>
   116→          <div className="flex gap-2">
   117→            <Button size="sm" variant="outline" className="border-green-200 text-green-700 hover:bg-green-50" onClick={() => handleBulkAction('approve')}>
   118→              <CheckCircle2 className="w-4 h-4 mr-1" /> Approva
   119→            </Button>
   120→            <Button size="sm" variant="outline" className="border-red-200 text-red-700 hover:bg-red-50" onClick={() => handleBulkAction('reject')}>
   121→              <XCircle className="w-4 h-4 mr-1" /> Rifiuta
   122→            </Button>
   123→          </div>
   124→        </div>
   125→      )}
   126→
   127→      <div className="bg-card rounded-xl border border-border/50 shadow-sm overflow-hidden">
   128→        <div className="overflow-x-auto">
   129→          <table className="w-full text-sm text-left">
   130→            <thead className="bg-muted/30 text-muted-foreground font-medium border-b border-border/50">
   131→              <tr>
   132→                <th className="p-4 w-12"><Checkbox checked={eventsData?.events?.length > 0 && selectedIds.length === eventsData?.events?.length} onCheckedChange={toggleAll} /></th>
   133→                <th className="p-4 min-w-[250px]">Titolo & Data</th>
   134→                <th className="p-4">Luogo</th>
   135→                <th className="p-4">Fonte</th>
   136→                <th className="p-4">Stato</th>
   137→                <th className="p-4 text-right">Azioni</th>
   138→              </tr>
   139→            </thead>
   140→            <tbody className="divide-y divide-border/30">
   141→              {isLoading ? (
   142→                <tr><td colSpan={6} className="p-8 text-center text-muted-foreground animate-pulse">Caricamento...</td></tr>
   143→              ) : eventsData?.events?.length === 0 ? (
   144→                <tr><td colSpan={6} className="p-12 text-center text-muted-foreground">Nessun evento trovato.</td></tr>
   145→              ) : (
   146→                eventsData?.events?.map(event => (
   147→                  <tr key={event.id} className="hover:bg-muted/10 transition-colors group">
   148→                    <td className="p-4"><Checkbox checked={selectedIds.includes(event.id)} onCheckedChange={() => toggleOne(event.id)} /></td>
   149→                    <td className="p-4">
   150→                      <div className="font-medium text-foreground text-base mb-1">{event.title}</div>
   151→                      <div className="flex items-center text-muted-foreground text-xs gap-2">
   152→                        <Clock className="w-3 h-3" />
   153→                        {event.dateDisplay || (event.dateStart ? format(new Date(event.dateStart), 'dd MMMM yyyy', { locale: it }) : 'Data sconosciuta')}
   154→                        {event.dateParseConfidence === 'low' && (
   155→                          <AlertTriangle className="w-3 h-3 text-amber-500 ml-1" title="Data parsing a bassa confidenza" />
   156→                        )}
   157→                      </div>
   158→                    </td>
   159→                    <td className="p-4 text-muted-foreground">
   160→                      {event.location ? (
   161→                        <div className="flex items-center gap-1.5 truncate max-w-[200px]">
   162→                          <MapPin className="w-3.5 h-3.5 shrink-0" />
   163→                          <span className="truncate">{event.location}</span>
   164→                        </div>
   165→                      ) : '-'}
   166→                    </td>
   167→                    <td className="p-4">
   168→                      <div className="flex flex-col gap-1 items-start">
   169→                        <span className="text-xs truncate max-w-[150px]">{event.sourceName || 'Manuale'}</span>
   170→                        <Badge variant="outline" className={`text-[10px] uppercase tracking-wider ${event.sourceType === 'manual' ? 'text-purple-600 border-purple-200' : 'text-blue-600 border-blue-200'}`}>
   171→                          {event.sourceType}
   172→                        </Badge>
   173→                      </div>
   174→                    </td>
   175→                    <td className="p-4">{getStatusBadge(event.status)}</td>
   176→                    <td className="p-4 text-right">
   177→                      <Button variant="ghost" size="icon" className="text-muted-foreground hover:text-primary">
   178→                        <Eye className="w-4 h-4" />
   179→                      </Button>
   180→                    </td>
   181→                  </tr>
   182→                ))
   183→              )}
   184→            </tbody>
   185→          </table>
   186→        </div>
   187→      </div>
   188→    </AppLayout>
   189→  );
   190→}
